#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint32_t storage;
};

static inline uint16_t float_to_half(float f) {
  union {
    float f;
    uint32_t u;
  } v{f};

  uint32_t sign = (v.u >> 16) & 0x8000u;
  uint32_t mantissa = v.u & 0x007fffffu;
  int32_t exp = static_cast<int32_t>((v.u >> 23) & 0xffu) - 127 + 15;

  if (exp <= 0) {
    if (exp < -10) return static_cast<uint16_t>(sign);
    mantissa = (mantissa | 0x00800000u) >> (1 - exp);
    return static_cast<uint16_t>(sign | ((mantissa + 0x00001000u) >> 13));
  }
  if (exp >= 31) {
    return static_cast<uint16_t>(sign | 0x7c00u);
  }

  return static_cast<uint16_t>(sign | (static_cast<uint32_t>(exp) << 10) |
                               ((mantissa + 0x00001000u) >> 13));
}

static inline float half_to_float(uint16_t h) {
  uint32_t sign = (static_cast<uint32_t>(h & 0x8000u)) << 16;
  uint32_t exp = (h >> 10) & 0x1fu;
  uint32_t mantissa = h & 0x03ffu;

  uint32_t out;
  if (exp == 0) {
    if (mantissa == 0) {
      out = sign;
    } else {
      exp = 1;
      while ((mantissa & 0x0400u) == 0) {
        mantissa <<= 1;
        --exp;
      }
      mantissa &= 0x03ffu;
      out = sign | ((exp + (127 - 15)) << 23) | (mantissa << 13);
    }
  } else if (exp == 31) {
    out = sign | 0x7f800000u | (mantissa << 13);
  } else {
    out = sign | ((exp + (127 - 15)) << 23) | (mantissa << 13);
  }

  union {
    uint32_t u;
    float f;
  } v{out};
  return v.f;
}

static inline uint16_t half2_low(const half2& h) {
  return static_cast<uint16_t>(h.storage & 0xffffu);
}
static inline uint16_t half2_high(const half2& h) {
  return static_cast<uint16_t>((h.storage >> 16) & 0xffffu);
}
static inline half2 make_half2(uint16_t lo, uint16_t hi) {
  half2 h;
  h.storage = static_cast<uint32_t>(lo) | (static_cast<uint32_t>(hi) << 16);
  return h;
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <>
inline half2 conv_int<half2>(const int i) {
  uint16_t h = float_to_half(static_cast<float>(i));
  return make_half2(h, h);
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  float a0 = half_to_float(half2_low(a));
  float a1 = half_to_float(half2_high(a));
  float b0 = half_to_float(half2_low(b));
  float b1 = half_to_float(half2_high(b));
  float c0 = half_to_float(half2_low(c));
  float c1 = half_to_float(half2_high(c));
  uint16_t r0 = float_to_half(a0 * b0 + c0);
  uint16_t r1 = float_to_half(a1 * b1 + c1);
  return make_half2(r0, r1);
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return a.storage == b.storage;
}

template <class T, int blockdim, unsigned int granularity,
          unsigned int fusion_degree, unsigned int compute_iterations,
          bool TemperateUnroll>
static void benchmark_func(T seed, T* g_data, long total_blocks) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const int stride = blockSize;
  const long long big_stride =
      static_cast<long long>(total_blocks) * blockSize * granularity;
  const long long total_threads = static_cast<long long>(total_blocks) * blockSize;

#pragma omp parallel for schedule(static)
  for (long long tid = 0; tid < total_threads; tid++) {
    const long long blockIdx = tid / blockSize;
    const int threadIdx = static_cast<int>(tid % blockSize);
    const long long idx = blockIdx * blockSize * granularity + threadIdx;

    T tmps[granularity];
    for (int k = 0; k < static_cast<int>(fusion_degree); k++) {
      for (unsigned int j = 0; j < granularity; j++) {
        tmps[j] = g_data[idx + j * stride + static_cast<long long>(k) * big_stride];
        for (unsigned int i = 0; i < compute_iterations; i++) {
          tmps[j] = mad(tmps[j], tmps[j], seed);
        }
      }

      T sum = conv_int<T>(0);
      for (unsigned int j = 0; j < granularity; j += 2) {
        sum = mad(tmps[j], tmps[j + 1], sum);
      }

      if (equal(sum, conv_int<T>(-1))) {
        g_data[idx + static_cast<long long>(k) * big_stride] = sum;
      }
    }
  }
}

template <typename F>
static float measure_ms(F&& f) {
  auto t0 = std::chrono::high_resolution_clock::now();
  f();
  auto t1 = std::chrono::high_resolution_clock::now();
  std::chrono::duration<float, std::milli> dt = t1 - t0;
  return dt.count();
}

static void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const long TOTAL_REDUCED_BLOCKS = reduced_grid_size / BLOCK_SIZE;

  benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

int out_config = 1;

template <unsigned int compute_iterations>
static void runbench(double* cd, long size, bool doHalfs) {
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const long TOTAL_BLOCKS = compute_grid_size / BLOCK_SIZE;
  const long long computations =
      (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
       (2 * ELEMENTS_PER_THREAD * compute_iterations) *
           (long long)compute_grid_size) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  float kernel_time_mad_sp = measure_ms([&]() {
    benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                   compute_iterations, false>(1.0f, reinterpret_cast<float*>(cd),
                                              TOTAL_BLOCKS);
  });

  float kernel_time_mad_dp = measure_ms([&]() {
    benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                   compute_iterations, false>(1.0, cd, TOTAL_BLOCKS);
  });

  float kernel_time_mad_hp = 0.f;
  if (doHalfs) {
    half2 h_ones;
    h_ones.storage = 15360u + (15360u << 16);
    kernel_time_mad_hp = measure_ms([&]() {
      benchmark_func<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                     compute_iterations, false>(h_ones,
                                                reinterpret_cast<half2*>(cd),
                                                TOTAL_BLOCKS);
    });
  }

  float kernel_time_mad_int = measure_ms([&]() {
    benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE,
                   compute_iterations, true>(1, reinterpret_cast<int*>(cd),
                                             TOTAL_BLOCKS);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,  "
      "%8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. /
          (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

